import{_ as e,r as p,o as c,c as o,a,b as n,d as l,e as s}from"./app-25fa875f.js";const i="/blog/assets/maven-cmd-42df631c.png",d="/blog/assets/maven-compile-5da3b4f0.png",u="/blog/assets/maven-clean-c22c126b.png",r={},g=s(`<h1 id="java-maven-项目构建工具" tabindex="-1"><a class="header-anchor" href="#java-maven-项目构建工具" aria-hidden="true">#</a> Java - Maven 项目构建工具</h1><p>Created by : Mr Dk.</p><p>2018 / 11 / 03 15:01</p><p>Nanjing, Jiangsu, China</p><hr><h2 id="about" tabindex="-1"><a class="header-anchor" href="#about" aria-hidden="true">#</a> About</h2><p><em>Apache Maven</em> 是一个项目管理和综合工具。提供一个 <strong>项目对象模型文件 (POM)</strong> 的概念来管理项目的构建、相关性和文档。还能够自动下载项目依赖库。</p><h2 id="installation" tabindex="-1"><a class="header-anchor" href="#installation" aria-hidden="true">#</a> Installation</h2><p>从 Apache official 上下载 Maven 的可执行文件并解压。</p><h3 id="windows" tabindex="-1"><a class="header-anchor" href="#windows" aria-hidden="true">#</a> Windows</h3><ol><li>添加环境变量 <code>MAVEN_HOME</code> - <code>C:\\Program Files\\apache-maven-3.6.3</code></li><li>在环境变量 <code>PATH</code> 中加入 <code>%MAVEN_HOME%\\bin</code></li></ol><h3 id="linux" tabindex="-1"><a class="header-anchor" href="#linux" aria-hidden="true">#</a> Linux</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vim</span> /etc/profile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>export MAVEN_HOME=/opt/module/apache-maven-3.3.9
export MAVEN_REPO=/opt/module/apache-maven-3.3.9/m2/repository
export PATH=$PATH:$MAVEN_HOME/bin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">source</span> /etc/profile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>检测是否成功:</p><div class="language-console line-numbers-mode" data-ext="console"><pre class="language-console"><code>$ mvn -version
Apache Maven 3.6.3 (cecedd343002696d0abb50b32b541b8a6ba2883f)
Maven home: C:\\Program Files\\apache-maven-3.6.3
Java version: 1.8.0_231, vendor: Oracle Corporation, runtime: C:\\Program Files\\Java\\jre1.8.0_231
Default locale: zh_CN, platform encoding: GBK
OS name: &quot;windows 10&quot;, version: &quot;10.0&quot;, arch: &quot;amd64&quot;, family: &quot;windows&quot;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="configuration" tabindex="-1"><a class="header-anchor" href="#configuration" aria-hidden="true">#</a> Configuration</h2>`,18),k=a("strong",null,"中央存储库",-1),v=a("code",null,"http://repo1.maven.org/maven2/",-1),m={href:"http://maven.apache.org/guides/mini/guide-mirror-settings.html",target:"_blank",rel:"noopener noreferrer"},b=s(`<p>首先找到 Maven 的配置文件：</p><ul><li>Windows 下 - <code>\${user.home}/.m2/settings.xml</code></li><li>Linux 下 - <code>/etc/maven/settings.xml</code> (似乎 Windows 也 OK？？？ 😧)</li></ul><p>在配置文件中加入国内镜像 (阿里云为例):</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>settings</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>mirrors</span><span class="token punctuation">&gt;</span></span>

    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>mirror</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>id</span><span class="token punctuation">&gt;</span></span>nexus-aliyun<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>id</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>name</span><span class="token punctuation">&gt;</span></span>Nexus aliyun<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>name</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>url</span><span class="token punctuation">&gt;</span></span>http://maven.aliyun.com/nexus/content/groups/public<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>url</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>mirrorOf</span><span class="token punctuation">&gt;</span></span>central<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>mirrorOf</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>mirror</span><span class="token punctuation">&gt;</span></span>

  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>mirrors</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>settings</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="project" tabindex="-1"><a class="header-anchor" href="#project" aria-hidden="true">#</a> Project</h2><p>在 Eclipse 中新建一个 Maven project，里面有很多个工程模板，根据需求选择 (一般选择 <code>quickstart</code> 即可)，填写 <code>groupId</code>、<code>artifactId</code>、<code>version</code>。Maven 通过这三个元素唯一确定一个工程：</p><ul><li><code>groupId</code> - the unique identifier of the organization or group that created the project</li><li><code>artifactId</code> - unique base name of the primary artifact being generated by this project</li><li><code>groupId</code> 和 <code>artifactId</code> 也会组合为源代码路径 <code>/src</code> 下的默认包名</li></ul><p>根据需要设置 <code>JRE System Library</code>。如果需要引入依赖：</p><ul><li>定位到工程根目录的 <code>pom.xml</code> 文件中的 <code>&lt;dependencies&gt;</code> 内</li><li>加入依赖的定义组 <code>&lt;dependency&gt;</code>，其中包括依赖项目的 <code>groupId</code>、<code>artifactId</code>、<code>version</code>，以及 <code>scope</code> (部署阶段，若不加则默认所有阶段)</li></ul><p>配置保存后 Maven 会将依赖的 <code>.jar</code> 文件下载到 <em>Maven</em> 默认的本地存储库下 - <code>\${user.home}/.m2/repository/</code>。<code>.jar</code> 文件下载完毕后，会出现在 <code>Build Path</code> 的 <code>Maven Dependencies</code> 中。之后直接在 <code>src/</code> 目录下进行编码即可，依赖的类可以随时被 <code>import</code>。</p><p>与当前工程有关的信息全部都在 <code>pom.xml</code> 中，包括各子路径的作用等。右键工程，点击 <code>Maven/Update Project</code> 可重新构建工程并下载依赖。</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>project</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependencies</span><span class="token punctuation">&gt;</span></span>

    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>junit<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>junit<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>3.8.1<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>scope</span><span class="token punctuation">&gt;</span></span>test<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>scope</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>

    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>dependency</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>io.vertx<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>vertx-core<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>3.5.4<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependency</span><span class="token punctuation">&gt;</span></span>

  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>dependencies</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>project</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="command" tabindex="-1"><a class="header-anchor" href="#command" aria-hidden="true">#</a> Command</h2><p>在 cmd 中直接运行命令</p><ul><li><code>mvn compile</code> - 将 Java 源文件编译为 <code>.class</code> 文件</li><li><code>mvn test</code> - 测试，并生成测试报告</li><li><code>mvn clean</code> - 将以前编译的 <code>.class</code> 文件删除</li><li><code>mvn package</code> - 打包</li><li><code>mvn install</code> - 打包并放入 <code>maven</code> 本地仓库中</li><li>...</li></ul><p>在 eclipse 中的操作步骤：</p><ul><li>选择 <code>Run As</code></li><li>选择 <code>Maven build </code></li><li>在其中的 <code>Goals</code> 中填入对应的命令 - 如 <code>compile</code>、<code>install</code> 等</li></ul><p>在 Visual Studio Code 中的 <em>Maven for Java</em> 插件的帮助下可直接运行命令：</p><p><img src="`+i+'" alt="maven-cmd"></p><p><code>mvn compile</code> 命令：</p><p><img src="'+d+'" alt="maven-compile"></p><p><code>mvn clean</code> 命令：</p><p><img src="'+u+`" alt="maven-clean"></p><p>编译前，需要在 <code>pom.xml</code> 文件中指定编译所需的 JDK 版本和编码格式，以及指定 <code>maven-compiler-plugins</code> 的版本 <code>&lt;version&gt;&lt;/version&gt;</code>。</p><div class="language-xml line-numbers-mode" data-ext="xml"><pre class="language-xml"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>build</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>plugins</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>plugin</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>groupId</span><span class="token punctuation">&gt;</span></span>org.apache.maven.plugins<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>groupId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>artifactId</span><span class="token punctuation">&gt;</span></span>maven-compiler-plugin<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>artifactId</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>version</span><span class="token punctuation">&gt;</span></span>3.6.0<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>version</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>configuration</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>source</span><span class="token punctuation">&gt;</span></span>1.8<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>source</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>target</span><span class="token punctuation">&gt;</span></span>1.8<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>target</span><span class="token punctuation">&gt;</span></span>
        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>encoding</span><span class="token punctuation">&gt;</span></span>UTF-8<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>encoding</span><span class="token punctuation">&gt;</span></span>
      <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>configuration</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>plugin</span><span class="token punctuation">&gt;</span></span>
  <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>plugins</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>build</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><hr><h2 id="summary" tabindex="-1"><a class="header-anchor" href="#summary" aria-hidden="true">#</a> Summary</h2><p>其实以前经常看到 <em>Maven</em> 这个东西，特别是在用别人的代码的时候但是没有花心思研究。</p><p>今天学习 <em>Vert.x</em> 框架的时候，写了一些 demo 准备上传到 GitHub 上，突然发现工程目录下 <code>lib/</code> 里的文件有 80 MB。包括 <em>Vert.x</em> 的各种 <code>.jar</code> 文件以及其依赖文件，传上去既影响速度也没有必要。所以把整个工程构建成 Maven project，这样不再需要上传依赖的库了。</p><hr>`,30);function h(x,f){const t=p("ExternalLinkIcon");return c(),o("div",null,[g,a("p",null,[n("Maven 默认从 "),k,n(" ("),v,n(") 自动下载依赖资源。由于国内的网络环境问题，可以修改 Maven 的配置文件，添加国内镜像，从而加快下载速度。官方文档教程："),a("a",m,[n("Apache Maven - Guide to Mirror Settings"),l(t)]),n("。")]),b])}const M=e(r,[["render",h],["__file","Java Maven.html.vue"]]);export{M as default};
